// 교육용 빅뱅 시뮬레이션 - 실제 결합 과정을 시각화
import * as THREE from "three";

/**
 * 쿼크-글루온 플라즈마 단계 (10^-12초)
 * 매우 뜨거운 상태에서 쿼크와 글루온이 자유롭게 움직인다
 */
export function createQuarkGluonPlasma(numParticles = 500000) {
  const geometry = new THREE.BufferGeometry();
  const positions = new Float32Array(numParticles * 3);
  const colors = new Float32Array(numParticles * 3);
  const velocities = new Float32Array(numParticles * 3); // 속도 저장

  // 쿼크: 빨강(업 쿼크), 초록(다운 쿼크), 파랑(스트레인지 쿼크)
  // 글루온: 흰색
  for (let i = 0; i < numParticles; i++) {
    // 중심에서 구 모양으로 분포
    const r = Math.random() * 1000;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    positions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);

    // 빠른 랜덤 움직임
    velocities[i * 3] = (Math.random() - 0.5) * 20;
    velocities[i * 3 + 1] = (Math.random() - 0.5) * 20;
    velocities[i * 3 + 2] = (Math.random() - 0.5) * 20;

    // 쿼크와 글루온 색상 랜덤
    const type = Math.random();
    if (type < 0.3) {
      // 업 쿼크: 빨강
      colors[i * 3] = 1.0;
      colors[i * 3 + 1] = 0.1;
      colors[i * 3 + 2] = 0.1;
    } else if (type < 0.6) {
      // 다운 쿼크: 초록
      colors[i * 3] = 0.1;
      colors[i * 3 + 1] = 1.0;
      colors[i * 3 + 2] = 0.1;
    } else if (type < 0.85) {
      // 스트레인지 쿼크: 파랑
      colors[i * 3] = 0.1;
      colors[i * 3 + 1] = 0.1;
      colors[i * 3 + 2] = 1.0;
    } else {
      // 글루온: 노란색
      colors[i * 3] = 1.0;
      colors[i * 3 + 1] = 1.0;
      colors[i * 3 + 2] = 0.1;
    }
  }
  geometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
  geometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));
  const material = new THREE.PointsMaterial({
    size: 1.5,
    vertexColors: true,
    sizeAttenuation: true
  });
  const points = new THREE.Points(geometry, material);
  points.userData.velocities = velocities;
  return {
    points,
    initialPositions: positions.slice()
  };
}

/**
 * 쿼크 결합 단계 (10^-6초)
 * 쿼크 3개가 모여 양성자/중성자 형성 - 실제 결합 과정 시각화
 */
export function createQuarkCombination(stageProgress) {
  const group = new THREE.Group();

  // 개별 쿼크들과 결합된 하드론들을 모두 표시
  const numHadronGroups = 100000; // 결합 중인 하드론 개수
  const quarkGeometry = new THREE.BufferGeometry();
  const hadronGeometry = new THREE.BufferGeometry();
  const bondGeometry = new THREE.BufferGeometry(); // 결합 과정 시각화용

  const quarkPositions = new Float32Array(numHadronGroups * 3 * 3); // 3쿼크 x 3좌표
  const quarkColors = new Float32Array(numHadronGroups * 3 * 3);
  const hadronPositions = new Float32Array(numHadronGroups * 3);
  const hadronColors = new Float32Array(numHadronGroups * 3);

  // 결합선 표현 (쿼크들을 연결하는 선들)
  const bondPositions = new Float32Array(numHadronGroups * 3 * 2 * 3); // 각 쿼크마다 2개의 선
  const bondColors = new Float32Array(numHadronGroups * 3 * 2 * 3);
  let bondIndex = 0;
  for (let i = 0; i < numHadronGroups; i++) {
    // 하드론의 중심 위치
    const hadronX = (Math.random() - 0.5) * 1000;
    const hadronY = (Math.random() - 0.5) * 1000;
    const hadronZ = (Math.random() - 0.5) * 1000;
    hadronPositions[i * 3] = hadronX;
    hadronPositions[i * 3 + 1] = hadronY;
    hadronPositions[i * 3 + 2] = hadronZ;
    const isProton = Math.random() > 0.5;
    if (isProton) {
      // 양성자: 빨강
      hadronColors[i * 3] = 0.9;
      hadronColors[i * 3 + 1] = 0.1;
      hadronColors[i * 3 + 2] = 0.1;
    } else {
      // 중성자: 파랑
      hadronColors[i * 3] = 0.1;
      hadronColors[i * 3 + 1] = 0.1;
      hadronColors[i * 3 + 2] = 0.9;
    }

    // 3개의 쿼크가 하드론으로 결합되는 과정
    const quarkPositionsThree = [];
    for (let q = 0; q < 3; q++) {
      const angle = q / 3 * Math.PI * 2 + Math.random() * 0.3;
      const distance = (1 - stageProgress) * 80 + stageProgress * 5; // 점차 가까워짐

      const qx = hadronX + Math.cos(angle) * distance;
      const qy = hadronY + Math.sin(angle) * distance;
      const qz = hadronZ + (Math.random() - 0.5) * distance;
      quarkPositions[(i * 3 + q) * 3] = qx;
      quarkPositions[(i * 3 + q) * 3 + 1] = qy;
      quarkPositions[(i * 3 + q) * 3 + 2] = qz;
      quarkPositionsThree.push([qx, qy, qz]);

      // 쿼크 색상
      const quarkType = (q + i * 97) % 3;
      if (quarkType === 0) {
        quarkColors[(i * 3 + q) * 3] = 1.0;
        quarkColors[(i * 3 + q) * 3 + 1] = 0.1 + stageProgress * 0.5;
        quarkColors[(i * 3 + q) * 3 + 2] = 0.1 + stageProgress * 0.5;
      } else if (quarkType === 1) {
        quarkColors[(i * 3 + q) * 3] = 0.1 + stageProgress * 0.5;
        quarkColors[(i * 3 + q) * 3 + 1] = 1.0;
        quarkColors[(i * 3 + q) * 3 + 2] = 0.1 + stageProgress * 0.5;
      } else {
        quarkColors[(i * 3 + q) * 3] = 0.1 + stageProgress * 0.5;
        quarkColors[(i * 3 + q) * 3 + 1] = 0.1 + stageProgress * 0.5;
        quarkColors[(i * 3 + q) * 3 + 2] = 1.0;
      }
    }

    // 결합 강도를 나타내는 선 그리기
    // 쿼크 0 ↔ 쿼크 1
    bondPositions[bondIndex * 3] = quarkPositionsThree[0][0];
    bondPositions[bondIndex * 3 + 1] = quarkPositionsThree[0][1];
    bondPositions[bondIndex * 3 + 2] = quarkPositionsThree[0][2];
    bondColors[bondIndex * 3] = 1.0 * stageProgress;
    bondColors[bondIndex * 3 + 1] = 0.5 * stageProgress;
    bondColors[bondIndex * 3 + 2] = 0.0;
    bondIndex++;
    bondPositions[bondIndex * 3] = quarkPositionsThree[1][0];
    bondPositions[bondIndex * 3 + 1] = quarkPositionsThree[1][1];
    bondPositions[bondIndex * 3 + 2] = quarkPositionsThree[1][2];
    bondColors[bondIndex * 3] = 1.0 * stageProgress;
    bondColors[bondIndex * 3 + 1] = 0.5 * stageProgress;
    bondColors[bondIndex * 3 + 2] = 0.0;
    bondIndex++;
  }

  // 쿼크들
  quarkGeometry.setAttribute("position", new THREE.BufferAttribute(quarkPositions, 3));
  quarkGeometry.setAttribute("color", new THREE.BufferAttribute(quarkColors, 3));
  const quarkMaterial = new THREE.PointsMaterial({
    size: 2 + stageProgress * 1,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 1 - stageProgress * 0.4
  });
  const quarkPoints = new THREE.Points(quarkGeometry, quarkMaterial);
  group.add(quarkPoints);

  // 결합선
  if (bondIndex > 0) {
    const bondPositionsTrimmed = bondPositions.slice(0, bondIndex * 3);
    const bondColorsTrimmed = bondColors.slice(0, bondIndex * 3);
    bondGeometry.setAttribute("position", new THREE.BufferAttribute(bondPositionsTrimmed, 3));
    bondGeometry.setAttribute("color", new THREE.BufferAttribute(bondColorsTrimmed, 3));
    const bondMaterial = new THREE.LineBasicMaterial({
      vertexColors: true,
      transparent: true,
      opacity: 0.3 + stageProgress * 0.5,
      linewidth: 1
    });
    const bondLines = new THREE.LineSegments(bondGeometry, bondMaterial);
    group.add(bondLines);
  }

  // 결합된 하드론들 (양성자/중성자)
  hadronGeometry.setAttribute("position", new THREE.BufferAttribute(hadronPositions, 3));
  hadronGeometry.setAttribute("color", new THREE.BufferAttribute(hadronColors, 3));
  const hadronMaterial = new THREE.PointsMaterial({
    size: 3 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: stageProgress * 0.8
  });
  const hadronPoints = new THREE.Points(hadronGeometry, hadronMaterial);
  group.add(hadronPoints);
  return group;
}

/**
 * 핵융합 단계 (1-3분)
 * 양성자와 중성자가 모여 원자핵 형성 (헬륨-4, 리튬 등)
 */
export function createNucleosynthesis(stageProgress) {
  const group = new THREE.Group();

  // 결합 전의 양성자/중성자들
  const numNuclei = 100000;
  const protonNeutronGeometry = new THREE.BufferGeometry();
  const fusionGeometry = new THREE.BufferGeometry();
  const pnPositions = new Float32Array(numNuclei * 2 * 3); // 양성자 + 중성자
  const pnColors = new Float32Array(numNuclei * 2 * 3);
  const fusionNucleiPositions = new Float32Array(numNuclei * 3);
  const fusionNucleiColors = new Float32Array(numNuclei * 3);
  for (let i = 0; i < numNuclei; i++) {
    // 융합된 핵의 중심
    const nucleusX = (Math.random() - 0.5) * 800;
    const nucleusY = (Math.random() - 0.5) * 800;
    const nucleusZ = (Math.random() - 0.5) * 800;
    fusionNucleiPositions[i * 3] = nucleusX;
    fusionNucleiPositions[i * 3 + 1] = nucleusY;
    fusionNucleiPositions[i * 3 + 2] = nucleusZ;

    // 융합된 핵의 종류 결정
    const nucleusType = i % 3;
    if (nucleusType === 0) {
      // 헬륨-4: 시안색
      fusionNucleiColors[i * 3] = 0.2 + stageProgress * 0.3;
      fusionNucleiColors[i * 3 + 1] = 0.8 + stageProgress * 0.2;
      fusionNucleiColors[i * 3 + 2] = 0.9;
    } else if (nucleusType === 1) {
      // 리튬: 초록색
      fusionNucleiColors[i * 3] = 0.2 + stageProgress * 0.5;
      fusionNucleiColors[i * 3 + 1] = 1.0;
      fusionNucleiColors[i * 3 + 2] = 0.2;
    } else {
      // 베릴륨: 노란색
      fusionNucleiColors[i * 3] = 1.0;
      fusionNucleiColors[i * 3 + 1] = 0.9 + stageProgress * 0.1;
      fusionNucleiColors[i * 3 + 2] = 0.2;
    }

    // 융합 전: 분리된 양성자/중성자들
    // 양성자 (빨강)
    const protonDistance = (1 - stageProgress) * 60 + stageProgress * 5;
    const protonAngle = Math.random() * Math.PI * 2;
    pnPositions[i * 2 * 3] = nucleusX + Math.cos(protonAngle) * protonDistance;
    pnPositions[i * 2 * 3 + 1] = nucleusY + Math.sin(protonAngle) * protonDistance;
    pnPositions[i * 2 * 3 + 2] = nucleusZ + Math.random() * protonDistance * 0.5;
    pnColors[i * 2 * 3] = 1.0;
    pnColors[i * 2 * 3 + 1] = 0.1 + (1 - stageProgress) * 0.5;
    pnColors[i * 2 * 3 + 2] = 0.1 + (1 - stageProgress) * 0.5;

    // 중성자 (파랑)
    const neutronDistance = (1 - stageProgress) * 60 + stageProgress * 5;
    const neutronAngle = protonAngle + Math.PI;
    pnPositions[i * 2 * 3 + 3] = nucleusX + Math.cos(neutronAngle) * neutronDistance;
    pnPositions[i * 2 * 3 + 4] = nucleusY + Math.sin(neutronAngle) * neutronDistance;
    pnPositions[i * 2 * 3 + 5] = nucleusZ + Math.random() * neutronDistance * 0.5;
    pnColors[i * 2 * 3 + 3] = 0.1 + (1 - stageProgress) * 0.5;
    pnColors[i * 2 * 3 + 4] = 0.1 + (1 - stageProgress) * 0.5;
    pnColors[i * 2 * 3 + 5] = 1.0;
  }

  // 개별 양성자/중성자
  protonNeutronGeometry.setAttribute("position", new THREE.BufferAttribute(pnPositions, 3));
  protonNeutronGeometry.setAttribute("color", new THREE.BufferAttribute(pnColors, 3));
  const pnMaterial = new THREE.PointsMaterial({
    size: 2.5 + (1 - stageProgress) * 1,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: (1 - stageProgress) * 0.9
  });
  const pnPoints = new THREE.Points(protonNeutronGeometry, pnMaterial);
  group.add(pnPoints);

  // 융합된 핵들
  fusionGeometry.setAttribute("position", new THREE.BufferAttribute(fusionNucleiPositions, 3));
  fusionGeometry.setAttribute("color", new THREE.BufferAttribute(fusionNucleiColors, 3));
  const fusionMaterial = new THREE.PointsMaterial({
    size: 4 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: stageProgress * 0.9
  });
  const fusionPoints = new THREE.Points(fusionGeometry, fusionMaterial);
  group.add(fusionPoints);
  return group;
}

/**
 * 원자 형성 단계 (38만년)
 * 전자가 핵을 감싸며 중성 원자 형성 (수소, 헬륨)
 */
export function createAtomFormation(stageProgress) {
  const group = new THREE.Group();

  // 많은 원자 시스템 생성
  const numAtoms = 80000;

  // 각 원자의 핵 위치
  const atomCenters = [];
  for (let i = 0; i < numAtoms; i++) {
    atomCenters.push({
      x: (Math.random() - 0.5) * 1200,
      y: (Math.random() - 0.5) * 1200,
      z: (Math.random() - 0.5) * 1200,
      isHydrogen: Math.random() > 0.3 // 70% 수소, 30% 헬륨
    });
  }

  // 핵 (중심)
  const nucleusGeometry = new THREE.BufferGeometry();
  const nucleusPositions = new Float32Array(numAtoms * 3);
  const nucleusColors = new Float32Array(numAtoms * 3);
  for (let i = 0; i < numAtoms; i++) {
    nucleusPositions[i * 3] = atomCenters[i].x;
    nucleusPositions[i * 3 + 1] = atomCenters[i].y;
    nucleusPositions[i * 3 + 2] = atomCenters[i].z;

    // 핵: 노란색 (양성자/중성자 덩어리)
    nucleusColors[i * 3] = 1.0;
    nucleusColors[i * 3 + 1] = 0.8;
    nucleusColors[i * 3 + 2] = 0.1;
  }
  nucleusGeometry.setAttribute("position", new THREE.BufferAttribute(nucleusPositions, 3));
  nucleusGeometry.setAttribute("color", new THREE.BufferAttribute(nucleusColors, 3));
  const nucleusMaterial = new THREE.PointsMaterial({
    size: 4 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true
  });
  const nucleusPoints = new THREE.Points(nucleusGeometry, nucleusMaterial);
  group.add(nucleusPoints);

  // 전자 구름 (궤도 주변)
  // 수소: 1개 전자, 헬륨: 2개 전자
  const totalElectrons = numAtoms * 1.3; // 평균 1.3개
  const electronGeometry = new THREE.BufferGeometry();
  const electronPositions = new Float32Array(Math.floor(totalElectrons) * 3);
  const electronColors = new Float32Array(Math.floor(totalElectrons) * 3);
  let electronIdx = 0;
  for (let i = 0; i < numAtoms; i++) {
    const numElectrons = atomCenters[i].isHydrogen ? 1 : 2;
    const orbitRadius = 60 + (atomCenters[i].isHydrogen ? 0 : 40);
    for (let e = 0; e < numElectrons && electronIdx < totalElectrons; e++) {
      // 전자들이 궤도를 따라 분포
      const angle = e / numElectrons * Math.PI * 2 + Math.random() * 0.2;
      const verticalAngle = Math.acos(Math.random() * 2 - 1);
      electronPositions[electronIdx * 3] = atomCenters[i].x + Math.sin(verticalAngle) * Math.cos(angle) * orbitRadius;
      electronPositions[electronIdx * 3 + 1] = atomCenters[i].y + Math.sin(verticalAngle) * Math.sin(angle) * orbitRadius;
      electronPositions[electronIdx * 3 + 2] = atomCenters[i].z + Math.cos(verticalAngle) * orbitRadius;

      // 전자: 청록색 (점차 명확해짐)
      electronColors[electronIdx * 3] = 0.2 + stageProgress * 0.5;
      electronColors[electronIdx * 3 + 1] = 0.9 + stageProgress * 0.1;
      electronColors[electronIdx * 3 + 2] = 1.0;
      electronIdx++;
    }
  }
  electronGeometry.setAttribute("position", new THREE.BufferAttribute(electronPositions, 3));
  electronGeometry.setAttribute("color", new THREE.BufferAttribute(electronColors, 3));
  const electronMaterial = new THREE.PointsMaterial({
    size: 2 + stageProgress * 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.4 + stageProgress * 0.6
  });
  const electronPoints = new THREE.Points(electronGeometry, electronMaterial);
  group.add(electronPoints);
  return group;
}

